"$filePath = \"..\\app\\me\\page.tsx\"\n$content = Get-Content $filePath -Raw\n\n# Find the section after \"Công thức\" and add privacy/terms links before the reset button\n$pattern = '(<div style={{ padding: \"13px 16px\", borderBottom: \"0\\.5px solid var\\(--sep\\)\", display: \"flex\", justifyContent: \"space-between\" }}>\s*<span style={{ fontSize: 14, color: \"var\\(--text2\\)\\\" }}>C[^<]*</span>\s*<span style={{ fontSize: 14, fontWeight: 700, color: \"var\\(--text\\)\\\" }}>99[^<]*</span>\s*</div>)'\n\n$replacement = '$1<div style={{ borderBottom: \"0.5px solid var(--sep)\" }}><MenuItem icon=\"🔒\" iconBg=\"#E8F0F8\" title=\"Chính sách bảo mật\" sub=\"Xem cách chúng tôi bảo vệ dữ liệu\" href=\"/privacy\" /></div><div style={{ borderBottom: \"0.5px solid var(--sep)\" }}><MenuItem icon=\"📜\" iconBg=\"#F8F0E8\" title=\"Điều khoản sử dụng\" sub=\"Quy định và trách nhiệm\" href=\"/terms\" /></div>'\n\n$newContent = $content -replace $pattern, $replacement\n\nSet-Content $filePath -Value $newContent -NoNewline\n\nWrite-Host \"✓ Updated me/page.tsx with Privacy Policy and Terms links\""